// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract VoteCounter {
    struct Proposal {
        string name;
        uint256 voteCount;
    }

    Proposal[] private proposals;
    mapping(address => bool) private hasVoted;
    uint256 private winningProposalIndex = 0;

    event VoteCast(address voter, uint256 proposalIndex);

    constructor(string[] memory _proposalNames) {
        for (uint256 i = 0; i < _proposalNames.length; i++) {
            proposals.push(Proposal({
                name: _proposalNames[i],
                voteCount: 0
            }));
        }
    }

    function castVote(uint256 proposalIndex) external {
        require(!hasVoted[msg.sender], "Already voted");
        require(proposalIndex < proposals.length, "Invalid proposal index");

        proposals[proposalIndex].voteCount++;
        hasVoted[msg.sender] = true;

        emit VoteCast(msg.sender, proposalIndex);

        updateWinningProposal();
    }

    function updateWinningProposal() internal {
        uint256 maxVotes = 0;
        uint256 newWinningProposalIndex = 0;
        for (uint256 i = 0; i < proposals.length; i++) {
            if (proposals[i].voteCount > maxVotes) {
                maxVotes = proposals[i].voteCount;
                newWinningProposalIndex = i;
            }
        }
        winningProposalIndex = newWinningProposalIndex;
    }

    function getWinningProposal() external view returns (uint256, string memory) {
        return (winningProposalIndex, proposals[winningProposalIndex].name);
    }
}
